from pieces import Piece, RedPiece, BlackPiece

class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        for row in range(3):
            for col in (1, 3, 5, 7):
                if (row + col) % 2 == 0:
                    piece = RedPiece(row, col)
                    self.board[row][col] = piece

        for row in range(5, 8):
            for col in (0, 2, 4, 6):
                if (row + col) % 2 == 0:
                    piece = BlackPiece(row, col)
                    self.board[row][col] = piece

    def display(self):
        board_str = "  a b c d e f g h\n"
        for i, row in enumerate(self.board):
            board_str += f"{8 - i} |{'|'.join(' ' if cell is None else str(cell) for cell in row)}|\n"
        return board_str

    def get_piece(self, position):
        row, col = position
        return self.board[row][col]

    def pieces(self):
        for row in self.board:
            for piece in row:
                if piece:
                    yield piece

    def is_valid_move(self, piece, move):
        start_row, start_col = move.start
        end_row, end_col = move.end
        delta_row, delta_col = end_row - start_row, end_col - start_col

        # Check basic movement rules
        if abs(delta_row) != 1 or abs(delta_col) not in (1, 2):
            return False

        # Check capture rule
        if abs(delta_col) == 2:
            capture_row = (start_row + end_row) // 2
            capture_col = (start_col + end_col) // 2
            captured_piece = self.get_piece((capture_row, capture_col))
            if not captured_piece or captured_piece.color == piece.color:
                return False

        # Check diagonal direction
        if piece.color == 'red' and delta_row < 0:
            return False
        elif piece.color == 'black' and delta_row > 0:
            return False

        return True

    def make_move(self, move):
        start_row, start_col = move.start
        end_row, end_col = move.end
        piece = self.get_piece((start_row, start_col))
        captured_pieces = []

        if abs(end_col - start_col) == 2:
            capture_row = (start_row + end_row) // 2
            capture_col = (start_col + end_col) // 2
            captured_piece = self.get_piece((capture_row, capture_col))
            self.remove_piece((capture_row, capture_col))
            captured_pieces.append(capture_piece)

        piece.move_to((end_row, end_col))

    def remove_piece(self, position):
        row, col = position
        self.board[row][col] = None

class Move:
