import re

class HumanPlayer:
    def __init__(self, color):
        self.color = color

    def get_move(self):
        while True:
            move_str = input(f"{self.color.capitalize()} Player, enter your move (e.g., a1-c3): ")
            if self.validate_move(move_str):
                return move_str
            else:
                print("Invalid move. Please try again.")

    @staticmethod
    def validate_move(move_str):
        pattern = re.compile(r'^[a-h][1-8]-[a-h][1-8]$')
        if not pattern.match(move_str):
            return False

        start_pos, end_pos = move_str.split('-')
        if (int(start_pos[1]) + ord(start_pos[0]) - 97) % 2 != 0 or \
           (int(end_pos[1]) + ord(end_pos[0]) - 97) % 2 != 0:
            return False

        return True
