# checkers.py

class Piece:
    EMPTY = 0
    RED = 1
    BLACK = 2
    RED_KING = 3
    BLACK_KING = 4

    def __init__(self, color):
        self.color = color
        self.king = False

    def promote(self):
        if self.color == Piece.RED and self.row == 0:
            self.king = True
        elif self.color == Piece.BLACK and self.row == 7:
            self.king = True

    def __str__(self):
        if self.color == Piece.EMPTY:
            return '.'
        elif self.color == Piece.RED:
            return 'R' if not self.king else 'r'
        elif self.color == Piece.BLACK:
            return 'B' if not self.king else 'b'

class Board:
    def __init__(self):
        self.board = [[Piece.EMPTY for _ in range(8)] for _ in range(8)]
        self.init_board()

    def init_board(self):
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece(Piece.BLACK)
        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece(Piece.RED)

    def draw_board(self):
        for row in self.board:
            print(' '.join(str(piece) for piece in row))
        print()

    def move_piece(self, from_pos, to_pos):
        from_row, from_col = from_pos
        to_row, to_col = to_pos

        if not (0 <= from_row < 8 and 0 <= from_col < 8 and
                0 <= to_row < 8 and 0 <= to_col < 8):
            raise ValueError("Invalid move positions")

        piece = self.board[from_row][from_col]
        if piece == Piece.EMPTY or (piece.color != 1 and piece.color != 2):
            raise ValueError("No piece at from position")

        if not (abs(to_row - from_row) in [1, 2] and abs(to_col - from_col) == 1):
            raise ValueError("Invalid move distance")

        if to_pos in self.get_possible_moves(from_pos):
            self.board[to_row][to_col] = piece
            self.board[from_row][from_col] = Piece.EMPTY

            if abs(to_row - from_row) == 2:
                capture_row = (to_row + from_row) // 2
                capture_col = (to_col + from_col) // 2
                self.board[capture_row][capture_col] = Piece.EMPTY

            piece.promote()

    def get_possible_moves(self, pos):
        row, col = pos
        moves = []

        if self.board[row][col].color == Piece.RED or self.board[row][col].king:
            if row > 0 and (col > 0 and self.board[row-1][col-1].color == Piece.EMPTY) and not (self.board[row][col].king and row != 0):
                moves.append((row-1, col-1))
            if row > 0 and (col < 7 and self.board[row-1][col+1].color == Piece.EMPTY) and not (self.board[row][col].king and row != 0):
                moves.append((row-1, col+1))

        if self.board[row][col].color == Piece.BLACK or self.board[row][col].king:
            if row < 7 and (col > 0 and self.board[row+1][col-1].color == Piece.EMPTY) and not (self.board[row][col].king and row != 7):
                moves.append((row+1, col-1))
            if row < 7 and (col < 7 and self.board[row+1][col+1].color == Piece.EMPTY) and not (self.board[row][col].king and row != 7):
                moves.append((row+1, col+1))

        return moves

def main():
    board = Board()
    turn = Piece.RED

    while True:
        board.draw_board()

        if turn == Piece.RED:
            print("Red's turn")
        else:
            print("Black's turn")

        from_pos = input("Enter move (e.g., 2,3 to 3,4): ").split(',')
        to_pos = input("Enter move (e.g., 3,4 to 4,5): ").split(',')

        from_row, from_col = int(from_pos[0]), int(from_pos[1])
        to_row, to_col = int(to_pos[0]), int(to_pos[1])

        try:
            board.move_piece((from_row, from_col), (to_row, to_col))
            turn = Piece.BLACK if turn == Piece.RED else Piece.RED
        except ValueError as e:
            print(e)

if __name__ == "__main__":
    main()
